class DSU {
  constructor(size) {
    this.parent = Array(size + 1).fill(0).map((_, i) => i);
  }

  find(x) {
    if (this.parent[x] !== x) {
      this.parent[x] = this.find(this.parent[x]);
    }
    return this.parent[x];
  }

  union(x, y) {
    const rootX = this.find(x);
    const rootY = this.find(y);
    if (rootX !== rootY) {
      this.parent[rootY] = rootX;
    }
  }
}

function solve(c, connections, queries) {
  const dsu = new DSU(c);
  for (const [u, v] of connections) {
    dsu.union(u, v);
  }

  const components = new Map();
  for (let i = 1; i <= c; i++) {
    const root = dsu.find(i);
    if (!components.has(root)) {
      components.set(root, []);
    }
    components.get(root).push(i);
  }

  for (const comp of components.values()) {
    comp.sort((a, b) => a - b);
  }

  const active = new Array(c + 1).fill(true);

  const result = [];

  for (const [type, x] of queries) {
    if (type === 1) {
      if (active[x]) {
        result.push(x);
      } else {
        const root = dsu.find(x);
        const component = components.get(root);
        let found = -1;
        for (const station of component) {
          if (active[station]) {
            found = station;
            break;
          }
        }
        result.push(found);
      }
    } else {
      active[x] = false;
    }
  }

  return result;
}
