function solve(c, connections, queries) {
  class DSU {
    constructor(n) {
      this.parent = Array(n + 1).fill(0).map((_, i) => i);
      this.rank = Array(n + 1).fill(0);
    }

    find(x) {
      if (this.parent[x] !== x) {
        this.parent[x] = this.find(this.parent[x]);
      }
      return this.parent[x];
    }

    union(x, y) {
      const xroot = this.find(x);
      const yroot = this.find(y);
      if (xroot === yroot) return;
      if (this.rank[xroot] < this.rank[yroot]) {
        this.parent[xroot] = yroot;
      } else {
        this.parent[yroot] = xroot;
        if (this.rank[xroot] === this.rank[yroot]) {
          this.rank[xroot]++;
        }
      }
    }
  }

  class MinHeap {
    constructor() {
      this.heap = [];
    }

    push(value) {
      this.heap.push(value);
      this.bubbleUp();
    }

    pop() {
      if (this.heap.length === 0) return null;
      const min = this.heap[0];
      this.heap[0] = this.heap.pop();
      this.bubbleDown();
      return min;
    }

    peek() {
      return this.heap[0];
    }

    isEmpty() {
      return this.heap.length === 0;
    }

    bubbleUp() {
      let index = this.heap.length - 1;
      while (index > 0) {
        const parentIndex = Math.floor((index - 1) / 2);
        if (this.heap[index] < this.heap[parentIndex]) {
          [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
          index = parentIndex;
        } else {
          break;
        }
      }
    }

    bubbleDown() {
      let index = 0;
      const length = this.heap.length;
      while (index < length) {
        const leftIndex = 2 * index + 1;
        const rightIndex = 2 * index + 2;
        let smallestIndex = index;
        if (leftIndex < length && this.heap[leftIndex] < this.heap[smallestIndex]) {
          smallestIndex = leftIndex;
        }
        if (rightIndex < length && this.heap[rightIndex] < this.heap[smallestIndex]) {
          smallestIndex = rightIndex;
        }
        if (smallestIndex !== index) {
          [this.heap[index], this.heap[smallestIndex]] = [this.heap[smallestIndex], this.heap[index]];
          index = smallestIndex;
        } else {
          break;
        }
      }
    }
  }

  const dsu = new DSU(c);
  for (const [u, v] of connections) {
    dsu.union(u, v);
  }

  const componentHeaps = new Map();
  const active = new Array(c + 1).fill(true);

  for (let i = 1; i <= c; i++) {
    const root = dsu.find(i);
    if (!componentHeaps.has(root)) {
      componentHeaps.set(root, new MinHeap());
    }
    componentHeaps.get(root).push(i);
  }

  const result = [];
  for (const [type, x] of queries) {
    if (type === 1) {
      if (active[x]) {
        result.push(x);
      } else {
        const root = dsu.find(x);
        const heap = componentHeaps.get(root);
        while (!heap.isEmpty() && !active[heap.peek()]) {
          heap.pop();
        }
        if (heap.isEmpty()) {
          result.push(-1);
        } else {
          result.push(heap.peek());
        }
      }
    } else {
      active[x] = false;
    }
  }

  return result;
}
